import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void rectangularTwoByThree() {
        int[][] input = {{1, 2, 3}, {4, 5, 6}};
        int[][] result = new Solution().transpose(input);
        assertArrayEquals(new int[][]{{1, 4}, {2, 5}, {3, 6}}, result);
    }

    @Test
    void rectangularThreeByOne() {
        int[][] input = {{1}, {2}, {3}};
        int[][] result = new Solution().transpose(input);
        assertArrayEquals(new int[][]{{1, 2, 3}}, result);
    }

    @Test
    void squareThreeByThree() {
        int[][] input = {{1, 2, 3}, {4, 5, 6}, {7, 8, 9}};
        int[][] result = new Solution().transpose(input);
        assertArrayEquals(new int[][]{{1, 4, 7}, {2, 5, 8}, {3, 6, 9}}, result);
    }

    @Test
    void singleCell() {
        int[][] input = {{42}};
        int[][] result = new Solution().transpose(input);
        assertArrayEquals(new int[][]{{42}}, result);
    }

    @Test
    void emptyMatrix() {
        int[][] input = {};
        int[][] result = new Solution().transpose(input);
        assertEquals(0, result.length);
    }

    @Test
    void newArrayIndependence() {
        // Transpose must return a NEW array, not the input itself
        int[][] input = {{1, 2}, {3, 4}};
        int[][] result = new Solution().transpose(input);
        assertNotSame(input, result);
        assertArrayEquals(new int[][]{{1, 3}, {2, 4}}, result);
    }

    @Test
    void fourByTwo() {
        int[][] input = {{1, 2}, {3, 4}, {5, 6}, {7, 8}};
        int[][] result = new Solution().transpose(input);
        assertArrayEquals(new int[][]{{1, 3, 5, 7}, {2, 4, 6, 8}}, result);
    }
}
